/**
 * QRCode.js - Standard compliant QR Code generator
 * Creates actual scannable QR codes following ISO/IEC 18004 standard
 */
(function(global) {
    'use strict';
    
    // QR Code error correction levels
    const ErrorCorrectionLevel = { L: 1, M: 0, Q: 3, H: 2 };
    
    // Galois field arithmetic
    function QRMath() {}
    QRMath.glog = function(n) {
        if (n < 1) throw new Error("glog(" + n + ")");
        return QRMath.LOG_TABLE[n];
    };
    
    QRMath.gexp = function(n) {
        while (n < 0) n += 255;
        while (n >= 256) n -= 255;
        return QRMath.EXP_TABLE[n];
    };
    
    QRMath.EXP_TABLE = new Array(256);
    QRMath.LOG_TABLE = new Array(256);
    
    for (let i = 0; i < 8; i++) {
        QRMath.EXP_TABLE[i] = 1 << i;
    }
    for (let i = 8; i < 256; i++) {
        QRMath.EXP_TABLE[i] = QRMath.EXP_TABLE[i - 4]
            ^ QRMath.EXP_TABLE[i - 5]
            ^ QRMath.EXP_TABLE[i - 6]
            ^ QRMath.EXP_TABLE[i - 8];
    }
    for (let i = 0; i < 255; i++) {
        QRMath.LOG_TABLE[QRMath.EXP_TABLE[i]] = i;
    }
    
    // QR Code implementation
    function QRCode(text, options = {}) {
        this.typeNumber = options.typeNumber || 4;
        this.errorCorrectionLevel = options.errorCorrectionLevel || ErrorCorrectionLevel.M;
        this.modules = null;
        this.moduleCount = 0;
        this.dataCache = null;
        this.dataList = [];
        
        this.addData(text);
        this.make();
    }
    
    QRCode.prototype = {
        addData: function(data) {
            const newData = new QR8bitByte(data);
            this.dataList.push(newData);
            this.dataCache = null;
        },
        
        isDark: function(row, col) {
            if (row < 0 || this.moduleCount <= row || col < 0 || this.moduleCount <= col) {
                throw new Error(row + "," + col);
            }
            return this.modules[row][col];
        },
        
        getModuleCount: function() {
            return this.moduleCount;
        },
        
        make: function() {
            this.makeImpl(false, this.getBestMaskPattern());
        },
        
        makeImpl: function(test, maskPattern) {
            this.moduleCount = this.typeNumber * 4 + 17;
            this.modules = new Array(this.moduleCount);
            
            for (let row = 0; row < this.moduleCount; row++) {
                this.modules[row] = new Array(this.moduleCount);
                for (let col = 0; col < this.moduleCount; col++) {
                    this.modules[row][col] = null;
                }
            }
            
            this.setupPositionProbePattern(0, 0);
            this.setupPositionProbePattern(this.moduleCount - 7, 0);
            this.setupPositionProbePattern(0, this.moduleCount - 7);
            this.setupPositionAdjustPattern();
            this.setupTimingPattern();
            this.setupTypeInfo(test, maskPattern);
            
            if (this.typeNumber >= 7) {
                this.setupVersionNumber(test);
            }
            
            if (this.dataCache == null) {
                this.dataCache = QRCode.createData(this.typeNumber, this.errorCorrectionLevel, this.dataList);
            }
            
            this.mapData(this.dataCache, maskPattern);
        },
        
        setupPositionProbePattern: function(row, col) {
            for (let r = -1; r <= 7; r++) {
                if (row + r <= -1 || this.moduleCount <= row + r) continue;
                
                for (let c = -1; c <= 7; c++) {
                    if (col + c <= -1 || this.moduleCount <= col + c) continue;
                    
                    if ((0 <= r && r <= 6 && (c == 0 || c == 6))
                        || (0 <= c && c <= 6 && (r == 0 || r == 6))
                        || (2 <= r && r <= 4 && 2 <= c && c <= 4)) {
                        this.modules[row + r][col + c] = true;
                    } else {
                        this.modules[row + r][col + c] = false;
                    }
                }
            }
        },
        
        getBestMaskPattern: function() {
            let minLostPoint = 0;
            let pattern = 0;
            
            for (let i = 0; i < 8; i++) {
                this.makeImpl(true, i);
                const lostPoint = QRUtil.getLostPoint(this);
                
                if (i == 0 || minLostPoint > lostPoint) {
                    minLostPoint = lostPoint;
                    pattern = i;
                }
            }
            
            return pattern;
        },
        
        setupTimingPattern: function() {
            for (let r = 8; r < this.moduleCount - 8; r++) {
                if (this.modules[r][6] != null) continue;
                this.modules[r][6] = (r % 2 == 0);
            }
            
            for (let c = 8; c < this.moduleCount - 8; c++) {
                if (this.modules[6][c] != null) continue;
                this.modules[6][c] = (c % 2 == 0);
            }
        },
        
        setupPositionAdjustPattern: function() {
            const pos = QRUtil.getPatternPosition(this.typeNumber);
            
            for (let i = 0; i < pos.length; i++) {
                for (let j = 0; j < pos.length; j++) {
                    const row = pos[i];
                    const col = pos[j];
                    
                    if (this.modules[row][col] != null) continue;
                    
                    for (let r = -2; r <= 2; r++) {
                        for (let c = -2; c <= 2; c++) {
                            if (r == -2 || r == 2 || c == -2 || c == 2 || (r == 0 && c == 0)) {
                                this.modules[row + r][col + c] = true;
                            } else {
                                this.modules[row + r][col + c] = false;
                            }
                        }
                    }
                }
            }
        },
        
        setupTypeInfo: function(test, maskPattern) {
            const data = (this.errorCorrectionLevel << 3) | maskPattern;
            const bits = QRUtil.getBCHTypeInfo(data);
            
            // vertical
            for (let i = 0; i < 15; i++) {
                const mod = (!test && ((bits >> i) & 1) == 1);
                
                if (i < 6) {
                    this.modules[i][8] = mod;
                } else if (i < 8) {
                    this.modules[i + 1][8] = mod;
                } else {
                    this.modules[this.moduleCount - 15 + i][8] = mod;
                }
            }
            
            // horizontal
            for (let i = 0; i < 15; i++) {
                const mod = (!test && ((bits >> i) & 1) == 1);
                
                if (i < 8) {
                    this.modules[8][this.moduleCount - i - 1] = mod;
                } else if (i < 9) {
                    this.modules[8][15 - i - 1 + 1] = mod;
                } else {
                    this.modules[8][15 - i - 1] = mod;
                }
            }
            
            // fixed module
            this.modules[this.moduleCount - 8][8] = (!test);
        },
        
        setupVersionNumber: function(test) {
            const bits = QRUtil.getBCHVersionInfo(this.typeNumber);
            
            for (let i = 0; i < 18; i++) {
                const mod = (!test && ((bits >> i) & 1) == 1);
                this.modules[Math.floor(i / 3)][i % 3 + this.moduleCount - 8 - 3] = mod;
            }
            
            for (let i = 0; i < 18; i++) {
                const mod = (!test && ((bits >> i) & 1) == 1);
                this.modules[i % 3 + this.moduleCount - 8 - 3][Math.floor(i / 3)] = mod;
            }
        },
        
        mapData: function(data, maskPattern) {
            let inc = -1;
            let row = this.moduleCount - 1;
            let bitIndex = 7;
            let byteIndex = 0;
            
            for (let col = this.moduleCount - 1; col > 0; col -= 2) {
                if (col == 6) col--;
                
                while (true) {
                    for (let c = 0; c < 2; c++) {
                        if (this.modules[row][col - c] == null) {
                            let dark = false;
                            
                            if (byteIndex < data.length) {
                                dark = (((data[byteIndex] >>> bitIndex) & 1) == 1);
                            }
                            
                            const mask = QRUtil.getMask(maskPattern, row, col - c);
                            
                            if (mask) {
                                dark = !dark;
                            }
                            
                            this.modules[row][col - c] = dark;
                            bitIndex--;
                            
                            if (bitIndex == -1) {
                                byteIndex++;
                                bitIndex = 7;
                            }
                        }
                    }
                    
                    row += inc;
                    
                    if (row < 0 || this.moduleCount <= row) {
                        row -= inc;
                        inc = -inc;
                        break;
                    }
                }
            }
        }
    };
    
    // Utility functions
    const QRUtil = {
        PATTERN_POSITION_TABLE: [
            [],
            [6, 18],
            [6, 22],
            [6, 26],
            [6, 30],
            [6, 34],
            [6, 22, 38],
            [6, 24, 42],
            [6, 26, 46],
            [6, 28, 50],
            [6, 30, 54],
            [6, 32, 58],
            [6, 34, 62],
            [6, 26, 46, 66],
            [6, 26, 48, 70],
            [6, 26, 50, 74],
            [6, 30, 54, 78],
            [6, 30, 56, 82],
            [6, 30, 58, 86],
            [6, 34, 62, 90]
        ],
        
        getPatternPosition: function(typeNumber) {
            return this.PATTERN_POSITION_TABLE[typeNumber - 1];
        },
        
        getMask: function(maskPattern, i, j) {
            switch (maskPattern) {
                case 0: return (i + j) % 2 == 0;
                case 1: return i % 2 == 0;
                case 2: return j % 3 == 0;
                case 3: return (i + j) % 3 == 0;
                case 4: return (Math.floor(i / 2) + Math.floor(j / 3)) % 2 == 0;
                case 5: return (i * j) % 2 + (i * j) % 3 == 0;
                case 6: return ((i * j) % 2 + (i * j) % 3) % 2 == 0;
                case 7: return ((i * j) % 3 + (i + j) % 2) % 2 == 0;
                default: throw new Error("bad maskPattern:" + maskPattern);
            }
        },
        
        getLostPoint: function(qrCode) {
            const moduleCount = qrCode.getModuleCount();
            let lostPoint = 0;
            
            // LEVEL1
            for (let row = 0; row < moduleCount; row++) {
                for (let col = 0; col < moduleCount; col++) {
                    let sameCount = 0;
                    const dark = qrCode.isDark(row, col);
                    
                    for (let r = -1; r <= 1; r++) {
                        if (row + r < 0 || moduleCount <= row + r) continue;
                        
                        for (let c = -1; c <= 1; c++) {
                            if (col + c < 0 || moduleCount <= col + c) continue;
                            if (r == 0 && c == 0) continue;
                            
                            if (dark == qrCode.isDark(row + r, col + c)) {
                                sameCount++;
                            }
                        }
                    }
                    
                    if (sameCount > 5) {
                        lostPoint += (3 + sameCount - 5);
                    }
                }
            }
            
            // LEVEL2
            for (let row = 0; row < moduleCount - 1; row++) {
                for (let col = 0; col < moduleCount - 1; col++) {
                    let count = 0;
                    if (qrCode.isDark(row, col)) count++;
                    if (qrCode.isDark(row + 1, col)) count++;
                    if (qrCode.isDark(row, col + 1)) count++;
                    if (qrCode.isDark(row + 1, col + 1)) count++;
                    if (count == 0 || count == 4) {
                        lostPoint += 3;
                    }
                }
            }
            
            return lostPoint;
        },
        
        getBCHTypeInfo: function(data) {
            let d = data << 10;
            while (this.getBCHDigit(d) - this.getBCHDigit(0x537) >= 0) {
                d ^= (0x537 << (this.getBCHDigit(d) - this.getBCHDigit(0x537)));
            }
            return ((data << 10) | d) ^ 0x5412;
        },
        
        getBCHVersionInfo: function(data) {
            let d = data << 12;
            while (this.getBCHDigit(d) - this.getBCHDigit(0x1f25) >= 0) {
                d ^= (0x1f25 << (this.getBCHDigit(d) - this.getBCHDigit(0x1f25)));
            }
            return (data << 12) | d;
        },
        
        getBCHDigit: function(data) {
            let digit = 0;
            while (data != 0) {
                digit++;
                data >>>= 1;
            }
            return digit;
        }
    };
    
    // 8-bit byte mode
    function QR8bitByte(data) {
        this.mode = 4; // MODE_8BIT_BYTE
        this.data = data;
    }
    
    QR8bitByte.prototype = {
        getLength: function() {
            return this.data.length;
        },
        
        write: function(buffer) {
            for (let i = 0; i < this.data.length; i++) {
                buffer.put(this.data.charCodeAt(i), 8);
            }
        }
    };
    
    // Bit buffer
    function QRBitBuffer() {
        this.buffer = [];
        this.length = 0;
    }
    
    QRBitBuffer.prototype = {
        get: function(index) {
            const bufIndex = Math.floor(index / 8);
            return ((this.buffer[bufIndex] >>> (7 - index % 8)) & 1) == 1;
        },
        
        put: function(num, length) {
            for (let i = 0; i < length; i++) {
                this.putBit(((num >>> (length - i - 1)) & 1) == 1);
            }
        },
        
        getLengthInBits: function() {
            return this.length;
        },
        
        putBit: function(bit) {
            const bufIndex = Math.floor(this.length / 8);
            if (this.buffer.length <= bufIndex) {
                this.buffer.push(0);
            }
            
            if (bit) {
                this.buffer[bufIndex] |= (0x80 >>> (this.length % 8));
            }
            
            this.length++;
        }
    };
    
    // Data creation
    QRCode.createData = function(typeNumber, errorCorrectionLevel, dataList) {
        const rsBlocks = QRRSBlock.getRSBlocks(typeNumber, errorCorrectionLevel);
        const buffer = new QRBitBuffer();
        
        for (let i = 0; i < dataList.length; i++) {
            const data = dataList[i];
            buffer.put(data.mode, 4);
            buffer.put(data.getLength(), QRUtil.getLengthInBits(data.mode, typeNumber));
            data.write(buffer);
        }
        
        // calc number of data bytes.
        let totalDataCount = 0;
        for (let i = 0; i < rsBlocks.length; i++) {
            totalDataCount += rsBlocks[i].dataCount;
        }
        
        if (buffer.getLengthInBits() + 4 <= totalDataCount * 8) {
            buffer.put(0, 4);
        }
        
        // padding
        while (buffer.getLengthInBits() % 8 != 0) {
            buffer.putBit(false);
        }
        
        // padding
        while (true) {
            if (buffer.getLengthInBits() >= totalDataCount * 8) break;
            buffer.put(0xEC, 8);
            
            if (buffer.getLengthInBits() >= totalDataCount * 8) break;
            buffer.put(0x11, 8);
        }
        
        return QRCode.createBytes(buffer, rsBlocks);
    };
    
    QRCode.createBytes = function(buffer, rsBlocks) {
        let offset = 0;
        let maxDcCount = 0;
        let maxEcCount = 0;
        
        const dcdata = new Array(rsBlocks.length);
        const ecdata = new Array(rsBlocks.length);
        
        for (let r = 0; r < rsBlocks.length; r++) {
            const dcCount = rsBlocks[r].dataCount;
            const ecCount = rsBlocks[r].totalCount - dcCount;
            
            maxDcCount = Math.max(maxDcCount, dcCount);
            maxEcCount = Math.max(maxEcCount, ecCount);
            
            dcdata[r] = new Array(dcCount);
            
            for (let i = 0; i < dcdata[r].length; i++) {
                dcdata[r][i] = 0xff & buffer.buffer[i + offset];
            }
            offset += dcCount;
            
            const rsPoly = QRUtil.getErrorCorrectPolynomial(ecCount);
            const rawPoly = new QRPolynomial(dcdata[r], rsPoly.getLength() - 1);
            
            const modPoly = rawPoly.mod(rsPoly);
            ecdata[r] = new Array(rsPoly.getLength() - 1);
            for (let i = 0; i < ecdata[r].length; i++) {
                const modIndex = i + modPoly.getLength() - ecdata[r].length;
                ecdata[r][i] = (modIndex >= 0) ? modPoly.get(modIndex) : 0;
            }
        }
        
        let totalCodeCount = 0;
        for (let i = 0; i < rsBlocks.length; i++) {
            totalCodeCount += rsBlocks[i].totalCount;
        }
        
        const data = new Array(totalCodeCount);
        let index = 0;
        
        for (let i = 0; i < maxDcCount; i++) {
            for (let r = 0; r < rsBlocks.length; r++) {
                if (i < dcdata[r].length) {
                    data[index++] = dcdata[r][i];
                }
            }
        }
        
        for (let i = 0; i < maxEcCount; i++) {
            for (let r = 0; r < rsBlocks.length; r++) {
                if (i < ecdata[r].length) {
                    data[index++] = ecdata[r][i];
                }
            }
        }
        
        return data;
    };
    
    // RS Block
    function QRRSBlock(totalCount, dataCount) {
        this.totalCount = totalCount;
        this.dataCount = dataCount;
    }
    
    QRRSBlock.RS_BLOCK_TABLE = [
        [1, 26, 19],
        [1, 26, 16],
        [1, 26, 13],
        [1, 26, 9],
        [1, 44, 34],
        [1, 44, 28],
        [1, 44, 22],
        [1, 44, 16],
        [1, 70, 55],
        [2, 35, 17],
        [2, 35, 13],
        [4, 17, 9],
        [1, 100, 80],
        [2, 50, 32],
        [2, 50, 24],
        [4, 25, 9],
        [1, 134, 108],
        [2, 67, 43],
        [2, 33, 15, 2, 34, 16],
        [2, 33, 11, 2, 34, 12]
    ];
    
    QRRSBlock.getRSBlocks = function(typeNumber, errorCorrectionLevel) {
        const rsBlock = QRRSBlock.getRsBlockTable(typeNumber, errorCorrectionLevel);
        
        if (rsBlock == undefined) {
            throw new Error("bad rs block @ typeNumber:" + typeNumber + "/errorCorrectionLevel:" + errorCorrectionLevel);
        }
        
        const length = rsBlock.length / 3;
        const list = [];
        
        for (let i = 0; i < length; i++) {
            const count = rsBlock[i * 3 + 0];
            const totalCount = rsBlock[i * 3 + 1];
            const dataCount = rsBlock[i * 3 + 2];
            
            for (let j = 0; j < count; j++) {
                list.push(new QRRSBlock(totalCount, dataCount));
            }
        }
        
        return list;
    };
    
    QRRSBlock.getRsBlockTable = function(typeNumber, errorCorrectionLevel) {
        switch(errorCorrectionLevel) {
            case ErrorCorrectionLevel.L:
                return QRRSBlock.RS_BLOCK_TABLE[(typeNumber - 1) * 4 + 0];
            case ErrorCorrectionLevel.M:
                return QRRSBlock.RS_BLOCK_TABLE[(typeNumber - 1) * 4 + 1];
            case ErrorCorrectionLevel.Q:
                return QRRSBlock.RS_BLOCK_TABLE[(typeNumber - 1) * 4 + 2];
            case ErrorCorrectionLevel.H:
                return QRRSBlock.RS_BLOCK_TABLE[(typeNumber - 1) * 4 + 3];
            default:
                return undefined;
        }
    };
    
    // Polynomial
    function QRPolynomial(num, shift) {
        if (num.length == undefined) {
            throw new Error(num.length + "/" + shift);
        }
        
        let offset = 0;
        
        while (offset < num.length && num[offset] == 0) {
            offset++;
        }
        
        this.num = new Array(num.length - offset + shift);
        for (let i = 0; i < num.length - offset; i++) {
            this.num[i] = num[i + offset];
        }
    }
    
    QRPolynomial.prototype = {
        get: function(index) {
            return this.num[index];
        },
        
        getLength: function() {
            return this.num.length;
        },
        
        multiply: function(e) {
            const num = new Array(this.getLength() + e.getLength() - 1);
            
            for (let i = 0; i < this.getLength(); i++) {
                for (let j = 0; j < e.getLength(); j++) {
                    num[i + j] ^= QRMath.gexp(QRMath.glog(this.get(i)) + QRMath.glog(e.get(j)));
                }
            }
            
            return new QRPolynomial(num, 0);
        },
        
        mod: function(e) {
            if (this.getLength() - e.getLength() < 0) {
                return this;
            }
            
            const ratio = QRMath.glog(this.get(0)) - QRMath.glog(e.get(0));
            
            const num = new Array(this.getLength());
            
            for (let i = 0; i < this.getLength(); i++) {
                num[i] = this.get(i);
            }
            
            for (let i = 0; i < e.getLength(); i++) {
                num[i] ^= QRMath.gexp(QRMath.glog(e.get(i)) + ratio);
            }
            
            return (new QRPolynomial(num, 0)).mod(e);
        }
    };
    
    // Utility functions
    QRUtil.getLengthInBits = function(mode, type) {
        if (1 <= type && type < 10) {
            switch(mode) {
                case 1: return 10;
                case 2: return 9;
                case 4: return 8;
                case 8: return 8;
                default: throw new Error("mode:" + mode);
            }
        } else if (type < 27) {
            switch(mode) {
                case 1: return 12;
                case 2: return 11;
                case 4: return 16;
                case 8: return 10;
                default: throw new Error("mode:" + mode);
            }
        } else if (type < 41) {
            switch(mode) {
                case 1: return 14;
                case 2: return 13;
                case 4: return 16;
                case 8: return 12;
                default: throw new Error("mode:" + mode);
            }
        } else {
            throw new Error("type:" + type);
        }
    };
    
    QRUtil.getErrorCorrectPolynomial = function(errorCorrectLength) {
        let a = new QRPolynomial([1], 0);
        
        for (let i = 0; i < errorCorrectLength; i++) {
            a = a.multiply(new QRPolynomial([1, QRMath.gexp(i)], 0));
        }
        
        return a;
    };
    
    // Canvas API
    const QRCodeAPI = {
        toCanvas: function(canvas, text, options, callback) {
            try {
                options = options || {};
                const qr = new QRCode(text, {
                    typeNumber: options.version || 4,
                    errorCorrectionLevel: options.errorCorrectionLevel || ErrorCorrectionLevel.M
                });
                
                const moduleCount = qr.getModuleCount();
                const cellSize = Math.floor((options.width || 200) / moduleCount);
                const size = cellSize * moduleCount;
                
                canvas.width = size;
                canvas.height = size;
                
                const ctx = canvas.getContext('2d');
                ctx.fillStyle = options.color?.light || '#ffffff';
                ctx.fillRect(0, 0, size, size);
                
                ctx.fillStyle = options.color?.dark || '#000000';
                
                for (let row = 0; row < moduleCount; row++) {
                    for (let col = 0; col < moduleCount; col++) {
                        if (qr.isDark(row, col)) {
                            ctx.fillRect(col * cellSize, row * cellSize, cellSize, cellSize);
                        }
                    }
                }
                
                if (callback) setTimeout(() => callback(null), 0);
            } catch (error) {
                if (callback) setTimeout(() => callback(error), 0);
            }
        }
    };
    
    global.QRCode = QRCodeAPI;
    
})(typeof window !== 'undefined' ? window : this);